// Script Continued Below
// 2.8.0 - 2022-07-09 - raj - STRY0119137 - Stretch- Template UI Clean Up- Delete Top Template Task Confirmation Modal (moved delete to new script)
// 
function onSubmit() {
    var formAction = g_form.getActionName();
    if (formAction == 'delete_template_task') {
        confirmDeleteTemplateTask();
		// returning true opens UI Page but does not allow user interaction, then auto closes the UI Page
        return false;
    }	
}
function confirmDeleteTemplateTask() {
	// STRY0119137 - make sure the client always has the template number and template name

    var templateTaskNumberShortDescription = g_scratchpad.templateTaskNumber + ': ' + g_scratchpad.templateTaskName;
    var messageTitle = getMessage('Delete') + ' ' + templateTaskNumberShortDescription + '?';
	var isTopTemplateTask = false;

	if(g_scratchpad.topTemplateTaskId==g_form.getUniqueValue()){
		isTopTemplateTask = true;
	}
    // Use widget for Portal
    if (typeof spModal != 'undefined') {
        spModal.open({
            title: messageTitle,
            backdrop: 'static',
            widget: 'tasker_modal_delete_prompt',
            widgetInput: {
				'templateSysId': g_scratchpad.templateId,
                'templateTaskSysId': g_form.getUniqueValue(),
                'templateTaskNumberShortDescription': templateTaskNumberShortDescription,
				'isTopTemplateTask': isTopTemplateTask

            },
            buttons: [],
			// Hide the <div> with class modal-footer that gets auto inserted from spModal, adds an element style
			footerStyle: { 'display': 'none' }
        }).then(function() {
            //jslog('numberofsubtasks');
        });
        return false;
    } else if (typeof spModal == 'undefined') {
        // For Platform use UI Page named: delete_task_prompt
        var gm = new GlideModal('x_153465_discovert_tasker_delete_prompt');
        gm.setTitle(messageTitle);
		gm.setPreference('sysparm_templateSysId', g_scratchpad.templateId);
		gm.setPreference('sysparm_templateTaskNumberShortDescription', templateTaskNumberShortDescription);
        gm.setPreference('sysparm_templateTaskSysId', g_form.getUniqueValue());
		gm.setPreference('sysparm_isTopTemplateTask', isTopTemplateTask);
        gm.setWidth(550);
        gm.render();
    }
}
